import{_ as t,c as i,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Diff Views: Switch Types | plannotator","description":"Learn how to switch diff types in Plannotator code review. Switch between uncommitted, staged, last commit, and branch views from the dropdown menu.","frontmatter":{"title":"Diff Views: Switch Types | plannotator","sidebarTitle":"Diff Views","subtitle":"Switching Diff Views","description":"Learn how to switch diff types in Plannotator code review. Switch between uncommitted, staged, last commit, and branch views from the dropdown menu.","tags":["code-review","git","diff","tutorial"],"prerequisite":["code-review-basics"],"order":6},"headers":[],"relativePath":"backnotprop/plannotator/platforms/code-review-diff-types/index.md","filePath":"backnotprop/plannotator/platforms/code-review-diff-types/index.md"}'),n={name:"backnotprop/plannotator/platforms/code-review-diff-types/index.md"};function s(r,e,d,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="switching-diff-views" tabindex="-1">Switching Diff Views <a class="header-anchor" href="#switching-diff-views" aria-label="Permalink to &quot;Switching Diff Views&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>During code review, you&#39;ll be able to:</p><ul><li>Use the dropdown menu to quickly switch between 5 diff views</li><li>Understand the code change scope displayed by each view</li><li>Choose the appropriate diff type based on review needs</li><li>Avoid missing important changes due to selecting the wrong view</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><p><strong>Reviewing only working directory, missing staged files</strong>:</p><p>You run the <code>/plannotator-review</code> command, see some code changes, and add a few comments. But after committing, you discover that the review missed files that were already <code>git add</code>ed to the staging area—these files never appeared in the diff.</p><p><strong>Want to see overall differences between current branch and main branch</strong>:</p><p>You&#39;ve been developing on a feature branch for a few weeks and want to see all the changes made so far, but the default &quot;Uncommitted changes&quot; view only shows modifications from the past few days.</p><p><strong>Want to compare differences between two specific commits</strong>:</p><p>You want to confirm whether a bug fix is correct and need to compare the code before and after the fix, but you don&#39;t know how to make Plannotator display the diff of historical commits.</p><h2 id="when-to-use-this-technique" tabindex="-1">When to Use This Technique <a class="header-anchor" href="#when-to-use-this-technique" aria-label="Permalink to &quot;When to Use This Technique&quot;">​</a></h2><ul><li><strong>Comprehensive review</strong>: Review both working directory and staging area changes simultaneously</li><li><strong>Before branch merge</strong>: Check all changes in current branch relative to main/master</li><li><strong>Rollback review</strong>: Confirm what files were modified in the last commit</li><li><strong>Multi-person collaboration</strong>: Check code staged but not yet committed by colleagues</li></ul><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p>Git diff has many variants, each displaying different code scopes. Plannotator consolidates these variants into a single dropdown menu, so you don&#39;t need to remember complex git commands.</p><div class="info custom-block"><p class="custom-block-title">Git Diff Types Quick Reference</p><table tabindex="0"><thead><tr><th>diff type</th><th>scope</th><th>typical use case</th></tr></thead><tbody><tr><td>Uncommitted changes</td><td>working directory + staging area</td><td>Review all changes in current development</td></tr><tr><td>Staged changes</td><td>staging area only</td><td>Review content before committing</td></tr><tr><td>Unstaged changes</td><td>working directory only</td><td>Review changes not yet <code>git add</code>ed</td></tr><tr><td>Last commit</td><td>most recent commit</td><td>Rollback or review just-made commit</td></tr><tr><td>vs main</td><td>current branch vs default branch</td><td>Comprehensive check before branch merge</td></tr></tbody></table></div><p>Dropdown menu options dynamically change based on your Git status:</p><ul><li>If you&#39;re not on the default branch, the &quot;vs main&quot; option appears</li><li>If there are no staged files, the Staged view displays &quot;No staged changes&quot;</li></ul><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-start-code-review" tabindex="-1">Step 1: Start Code Review <a class="header-anchor" href="#step-1-start-code-review" aria-label="Permalink to &quot;Step 1: Start Code Review&quot;">​</a></h3><p><strong>Why</strong></p><p>You need to first open Plannotator&#39;s code review interface.</p><p><strong>Action</strong></p><p>Run in terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>You should see</strong></p><p>Browser opens code review page. Above the file tree on the left, there&#39;s a dropdown menu showing the current diff type (usually &quot;Uncommitted changes&quot;).</p><h3 id="step-2-switch-to-staged-view" tabindex="-1">Step 2: Switch to Staged View <a class="header-anchor" href="#step-2-switch-to-staged-view" aria-label="Permalink to &quot;Step 2: Switch to Staged View&quot;">​</a></h3><p><strong>Why</strong></p><p>View files that have been <code>git add</code>ed but not yet committed.</p><p><strong>Action</strong></p><ol><li>Click the dropdown menu above the file tree on the left</li><li>Select &quot;Staged changes&quot;</li></ol><p><strong>You should see</strong></p><ul><li>If there are staged files, the file tree displays these files</li><li>If there are no staged files, the main area displays: &quot;No staged changes. Stage some files with git add.&quot;</li></ul><h3 id="step-3-switch-to-last-commit-view" tabindex="-1">Step 3: Switch to Last Commit View <a class="header-anchor" href="#step-3-switch-to-last-commit-view" aria-label="Permalink to &quot;Step 3: Switch to Last Commit View&quot;">​</a></h3><p><strong>Why</strong></p><p>Review the code just committed to confirm there are no issues.</p><p><strong>Action</strong></p><ol><li>Open the dropdown menu again</li><li>Select &quot;Last commit&quot;</li></ol><p><strong>You should see</strong></p><ul><li>Displays all files modified in the most recent commit</li><li>Diff content shows differences between <code>HEAD~1..HEAD</code></li></ul><h3 id="step-4-switch-to-vs-main-view-if-available" tabindex="-1">Step 4: Switch to vs main View (if available) <a class="header-anchor" href="#step-4-switch-to-vs-main-view-if-available" aria-label="Permalink to &quot;Step 4: Switch to vs main View (if available)&quot;">​</a></h3><p><strong>Why</strong></p><p>View all changes in the current branch relative to the default branch.</p><p><strong>Action</strong></p><ol><li>Check if the dropdown menu has &quot;vs main&quot; or &quot;vs master&quot; option</li><li>If present, select it</li></ol><p><strong>You should see</strong></p><ul><li>File tree displays all files with differences between current branch and default branch</li><li>Diff content shows complete changes of <code>main..HEAD</code></li></ul><div class="tip custom-block"><p class="custom-block-title">Check Current Branch</p><p>If you can&#39;t see the &quot;vs main&quot; option, it means you&#39;re on the default branch. You can check the current branch with this command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abbrev-ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span></span></code></pre></div><p>Switch to a feature branch and try again:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div></div><h2 id="checklist-✅" tabindex="-1">Checklist ✅ <a class="header-anchor" href="#checklist-✅" aria-label="Permalink to &quot;Checklist ✅&quot;">​</a></h2><p>Confirm you&#39;ve mastered:</p><ul><li>[ ] Can find and open the diff type dropdown menu</li><li>[ ] Understand the differences between &quot;Uncommitted&quot;, &quot;Staged&quot;, and &quot;Last commit&quot;</li><li>[ ] Can identify when the &quot;vs main&quot; option appears</li><li>[ ] Know which diff type to use in which scenario</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="pitfall-1-only-reviewing-uncommitted-missing-staged-files" tabindex="-1">Pitfall 1: Only reviewing Uncommitted, missing Staged files <a class="header-anchor" href="#pitfall-1-only-reviewing-uncommitted-missing-staged-files" aria-label="Permalink to &quot;Pitfall 1: Only reviewing Uncommitted, missing Staged files&quot;">​</a></h3><p><strong>Symptom</strong></p><p>After committing, you discover that some staged files were missed in the review.</p><p><strong>Cause</strong></p><p>The Uncommitted view displays all changes in working directory and staging area (<code>git diff HEAD</code>), so staged files are included.</p><p><strong>Solution</strong></p><p>Before review, switch to Staged view to check once, or use Uncommitted view (which includes staging area).</p><h3 id="pitfall-2-didn-t-compare-to-main-before-branch-merge" tabindex="-1">Pitfall 2: Didn&#39;t compare to main before branch merge <a class="header-anchor" href="#pitfall-2-didn-t-compare-to-main-before-branch-merge" aria-label="Permalink to &quot;Pitfall 2: Didn&#39;t compare to main before branch merge&quot;">​</a></h3><p><strong>Symptom</strong></p><p>After merging to main, you discover that unrelated modifications were introduced.</p><p><strong>Cause</strong></p><p>Only reviewed commits from the past few days, didn&#39;t compare the entire branch&#39;s differences relative to main.</p><p><strong>Solution</strong></p><p>Use &quot;vs main&quot; view for a comprehensive check before merging.</p><h3 id="pitfall-3-think-switching-views-loses-comments" tabindex="-1">Pitfall 3: Think switching views loses comments <a class="header-anchor" href="#pitfall-3-think-switching-views-loses-comments" aria-label="Permalink to &quot;Pitfall 3: Think switching views loses comments&quot;">​</a></h3><p><strong>Symptom</strong></p><p>Afraid to switch diff types, worrying that previously added comments will disappear.</p><p><strong>Cause</strong></p><p>Misunderstood the switching mechanism.</p><p><strong>Actual Behavior</strong></p><p>When switching diff types, Plannotator retains previous comments—they may still be applicable, or you can manually delete irrelevant comments.</p><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>The 5 diff types supported by Plannotator:</p><table tabindex="0"><thead><tr><th>type</th><th>Git command</th><th>scenario</th></tr></thead><tbody><tr><td>Uncommitted</td><td><code>git diff HEAD</code></td><td>Review all changes in current development</td></tr><tr><td>Staged</td><td><code>git diff --staged</code></td><td>Review staging area before committing</td></tr><tr><td>Unstaged</td><td><code>git diff</code></td><td>Review working directory modifications</td></tr><tr><td>Last commit</td><td><code>git diff HEAD~1..HEAD</code></td><td>Rollback or review most recent commit</td></tr><tr><td>vs main</td><td><code>git diff main..HEAD</code></td><td>Comprehensive check before branch merge</td></tr></tbody></table><p>Switching views doesn&#39;t lose comments—you can view the same or new comments from different perspectives.</p><h2 id="next-up" tabindex="-1">Next Up <a class="header-anchor" href="#next-up" aria-label="Permalink to &quot;Next Up&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../advanced/url-sharing/">URL Sharing</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to compress review content into a URL to share with colleagues</li><li>How the recipient opens a shared review link</li><li>Limitations and considerations in share mode</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Diff type definitions</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L10-L15" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>10-15</td></tr><tr><td>Git context retrieval</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L79-L96" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>79-96</td></tr><tr><td>Run Git Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L101-L147" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>101-147</td></tr><tr><td>Diff switch handling</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L300-L331" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>300-331</td></tr><tr><td>Diff options rendering in file tree</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/components/FileTree.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/components/FileTree.tsx</code></a></td><td>-</td></tr></tbody></table><p><strong>Key Types</strong>:</p><ul><li><code>DiffType</code>: <code>&#39;uncommitted&#39; | &#39;staged&#39; | &#39;unstaged&#39; | &#39;last-commit&#39; | &#39;branch&#39;</code></li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>getGitContext()</code>: Get current branch, default branch, and available diff options</li><li><code>runGitDiff(diffType, defaultBranch)</code>: Execute corresponding git command based on diff type</li></ul><p><strong>Key APIs</strong>:</p><ul><li><code>POST /api/diff/switch</code>: Switch diff type, return new diff data</li></ul></details>',83)])])}const g=t(n,[["render",s]]);export{m as __pageData,g as default};
